create extension if not exists pgcrypto;
create type public.clinic_role as enum ('doctor','secretary');
create type public.rx_status as enum ('draft','signed','cancelled');
create table public.clinics(id uuid primary key default gen_random_uuid(),name text not null,created_at timestamptz not null default now());
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text not null,created_at timestamptz not null default now());
create table public.clinic_memberships(clinic_id uuid references public.clinics on delete cascade,user_id uuid references public.profiles on delete cascade,role public.clinic_role not null,primary key(clinic_id,user_id));
create table public.doctor_configs(clinic_id uuid primary key references public.clinics on delete cascade,config jsonb not null default '{}',updated_at timestamptz not null default now());
create table public.patients(id text primary key,clinic_id uuid not null references public.clinics,name_first text not null,name_last text not null,birth_date date not null,gender text not null check(gender in('M','F')),weight numeric check(weight between 0 and 500),allergies jsonb not null default '[]',clinical_data jsonb not null default '{}',phone text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.prescriptions(id text primary key,clinic_id uuid not null references public.clinics,patient_id text not null references public.patients,doctor_id uuid not null references public.profiles,prescription_number text not null,prescription_date date not null,status public.rx_status not null default 'draft',snapshot jsonb not null,signed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(clinic_id,prescription_number),check((status='signed' and signed_at is not null)or status<>'signed'));
create table public.prescription_items(id text primary key,prescription_id text not null references public.prescriptions on delete cascade,line_order int not null check(line_order between 1 and 200),payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(prescription_id,line_order));
create table public.secretary_invitations(id uuid primary key default gen_random_uuid(),clinic_id uuid not null references public.clinics on delete cascade,email text not null,token_hash text not null unique,invited_by uuid not null references public.profiles,expires_at timestamptz not null default(now()+interval '7 days'),claimed_at timestamptz,claimed_by uuid references public.profiles,unique(clinic_id,email));
create table public.audit_events(id bigint generated always as identity primary key,clinic_id uuid not null references public.clinics,actor_id uuid references public.profiles,action text not null,entity_type text not null,entity_id text not null,before_data jsonb,after_data jsonb,created_at timestamptz not null default now());
create schema private;revoke all on schema private from public,anon,authenticated;
create function private.is_member(cid uuid,wanted public.clinic_role default null)returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.clinic_memberships where clinic_id=cid and user_id=auth.uid()and(wanted is null or role=wanted))$$;
revoke all on function private.is_member(uuid,public.clinic_role)from public;grant usage on schema private to authenticated;grant execute on function private.is_member(uuid,public.clinic_role)to authenticated;
create function private.guard_signed_rx()returns trigger language plpgsql set search_path='' as $$begin if old.status='signed'then raise exception 'SIGNED_PRESCRIPTION_IMMUTABLE';end if;return coalesce(new,old);end$$;
create function private.guard_signed_item()returns trigger language plpgsql set search_path='' as $$begin if exists(select 1 from public.prescriptions where id=old.prescription_id and status='signed')then raise exception 'SIGNED_PRESCRIPTION_IMMUTABLE';end if;return coalesce(new,old);end$$;
create trigger immutable_rx before update or delete on public.prescriptions for each row execute function private.guard_signed_rx();create trigger immutable_item before update or delete on public.prescription_items for each row execute function private.guard_signed_item();
create function public.handle_new_user()returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,email)values(new.id,lower(coalesce(new.email,'')))on conflict(id)do update set email=excluded.email;return new;end$$;
revoke all on function public.handle_new_user()from public,anon,authenticated;create trigger auth_profile after insert or update of email on auth.users for each row execute function public.handle_new_user();
create function public.bootstrap_doctor()returns uuid language plpgsql security definer set search_path='' as $$declare cid uuid;begin select clinic_id into cid from public.clinic_memberships where user_id=auth.uid()limit 1;if cid is not null then return cid;end if;if auth.uid()is null then raise exception 'AUTH_REQUIRED';end if;insert into public.clinics(name)values('Cabinet médical')returning id into cid;insert into public.clinic_memberships values(cid,auth.uid(),'doctor');insert into public.doctor_configs(clinic_id)values(cid);return cid;end$$;
revoke all on function public.bootstrap_doctor()from public,anon;grant execute on function public.bootstrap_doctor()to authenticated;
create function public.create_secretary_invitation(invitee_email text)returns text language plpgsql security definer set search_path='' as $$declare cid uuid;t text:=encode(extensions.gen_random_bytes(24),'hex');begin select clinic_id into cid from public.clinic_memberships where user_id=auth.uid()and role='doctor';if cid is null then raise exception 'DOCTOR_REQUIRED';end if;insert into public.secretary_invitations(clinic_id,email,token_hash,invited_by)values(cid,lower(trim(invitee_email)),encode(extensions.digest(t,'sha256'),'hex'),auth.uid())on conflict(clinic_id,email)do update set token_hash=excluded.token_hash,expires_at=now()+interval '7 days',claimed_at=null;return t;end$$;
revoke all on function public.create_secretary_invitation(text)from public,anon;grant execute on function public.create_secretary_invitation(text)to authenticated;
create function public.claim_secretary_invitation(token text)returns uuid language plpgsql security definer set search_path='' as $$declare i public.secretary_invitations;e text;begin select email into e from public.profiles where id=auth.uid();select * into i from public.secretary_invitations where token_hash=encode(extensions.digest(token,'sha256'),'hex')and claimed_at is null and expires_at>now()for update;if i.id is null or lower(i.email)<>lower(e)then raise exception 'INVALID_INVITATION';end if;insert into public.clinic_memberships values(i.clinic_id,auth.uid(),'secretary');update public.secretary_invitations set claimed_at=now(),claimed_by=auth.uid()where id=i.id;return i.clinic_id;end$$;
revoke all on function public.claim_secretary_invitation(text)from public,anon;grant execute on function public.claim_secretary_invitation(text)to authenticated;
create function public.remove_secretary(member_id uuid)returns void language plpgsql security definer set search_path='' as $$declare cid uuid;begin select clinic_id into cid from public.clinic_memberships where user_id=auth.uid()and role='doctor';if cid is null then raise exception 'DOCTOR_REQUIRED';end if;delete from public.clinic_memberships where clinic_id=cid and user_id=member_id and role='secretary';end$$;
revoke all on function public.remove_secretary(uuid)from public,anon;grant execute on function public.remove_secretary(uuid)to authenticated;
alter table public.clinics enable row level security;alter table public.profiles enable row level security;alter table public.clinic_memberships enable row level security;alter table public.doctor_configs enable row level security;alter table public.patients enable row level security;alter table public.prescriptions enable row level security;alter table public.prescription_items enable row level security;alter table public.secretary_invitations enable row level security;alter table public.audit_events enable row level security;
create policy clinic_read on public.clinics for select to authenticated using(private.is_member(id));
create policy profile_read on public.profiles for select to authenticated using(id=auth.uid()or exists(select 1 from public.clinic_memberships a join public.clinic_memberships b using(clinic_id)where a.user_id=auth.uid()and a.role='doctor'and b.user_id=profiles.id));
create policy membership_read on public.clinic_memberships for select to authenticated using(user_id=auth.uid()or private.is_member(clinic_id,'doctor'));
create policy config_read on public.doctor_configs for select to authenticated using(private.is_member(clinic_id));create policy config_write on public.doctor_configs for update to authenticated using(private.is_member(clinic_id,'doctor'))with check(private.is_member(clinic_id,'doctor'));
create policy patient_read on public.patients for select to authenticated using(private.is_member(clinic_id));create policy patient_insert on public.patients for insert to authenticated with check(private.is_member(clinic_id));create policy patient_update on public.patients for update to authenticated using(private.is_member(clinic_id))with check(private.is_member(clinic_id));create policy patient_delete on public.patients for delete to authenticated using(private.is_member(clinic_id,'doctor'));
create policy rx_read on public.prescriptions for select to authenticated using(private.is_member(clinic_id,'doctor'));create policy item_read on public.prescription_items for select to authenticated using(exists(select 1 from public.prescriptions where id=prescription_id and private.is_member(clinic_id,'doctor')));create policy invite_read on public.secretary_invitations for select to authenticated using(private.is_member(clinic_id,'doctor'));create policy audit_read on public.audit_events for select to authenticated using(private.is_member(clinic_id,'doctor'));
grant usage on schema public to anon,authenticated;grant select on public.clinics,public.profiles,public.clinic_memberships,public.prescriptions,public.prescription_items,public.secretary_invitations,public.audit_events to authenticated;grant select,update on public.doctor_configs to authenticated;grant select,insert,update,delete on public.patients to authenticated;grant usage,select on all sequences in schema public to authenticated;
alter publication supabase_realtime add table public.doctor_configs,public.patients,public.prescriptions,public.prescription_items;
create policy rx_insert on public.prescriptions for insert to authenticated with check(private.is_member(clinic_id,'doctor')and doctor_id=auth.uid());create policy rx_update on public.prescriptions for update to authenticated using(private.is_member(clinic_id,'doctor')and status<>'signed')with check(private.is_member(clinic_id,'doctor')and doctor_id=auth.uid());create policy rx_delete on public.prescriptions for delete to authenticated using(private.is_member(clinic_id,'doctor')and status<>'signed');
create policy item_insert on public.prescription_items for insert to authenticated with check(exists(select 1 from public.prescriptions where id=prescription_id and private.is_member(clinic_id,'doctor')and status<>'signed'));create policy item_update on public.prescription_items for update to authenticated using(exists(select 1 from public.prescriptions where id=prescription_id and private.is_member(clinic_id,'doctor')and status<>'signed'))with check(exists(select 1 from public.prescriptions where id=prescription_id and private.is_member(clinic_id,'doctor')and status<>'signed'));create policy item_delete on public.prescription_items for delete to authenticated using(exists(select 1 from public.prescriptions where id=prescription_id and private.is_member(clinic_id,'doctor')and status<>'signed'));
create policy audit_insert on public.audit_events for insert to authenticated with check(private.is_member(clinic_id)and actor_id=auth.uid());grant insert,update,delete on public.prescriptions,public.prescription_items to authenticated;grant insert on public.audit_events to authenticated;
create function public.delete_own_account()returns void language plpgsql security definer set search_path='' as $$begin if exists(select 1 from public.clinic_memberships where user_id=auth.uid()and role='doctor')then raise exception 'DOCTOR_ACCOUNT_REQUIRES_ADMINISTRATIVE_EXPORT';end if;delete from auth.users where id=auth.uid();end$$;revoke all on function public.delete_own_account()from public,anon;grant execute on function public.delete_own_account()to authenticated;


